# Parse (x, y)
pairs = re.findall(r'\(([^,]+),\s*([^)]+)\)', data_str)
x = np.array([float(p[0]) for p in pairs])
y = np.array([float(p[1]) for p in pairs])

# Add noise
np.random.seed(42)
scale = np.concatenate([
    np.zeros(200),
    np.linspace(0, 2, 200), 
    np.linspace(2, 0.5, 200), 
    np.linspace(0.5, 1, 200),
    np.linspace(1.0, 0.1, len(y) - 4*200)
])
step_noise = np.random.normal(0, 0.002, size=len(y))
cum_noise = scale * np.cumsum(step_noise)
y_noisy = y + cum_noise

# Convert noisy curve back to string
noisy_str = " ".join(
    f"({int(xi)}, {yi:.4f})" for xi, yi in zip(x, y_noisy)
)
print(noisy_str)


# (Optional) plot
plt.figure()
plt.plot(x, y, label="Original")
plt.plot(x, y_noisy, linestyle='--', label="Noised")
for i in range(5):
    plt.plot([i*200, i*200], [0.8, 1.5], color='red')
plt.legend()
plt.show()
